import tensorflow as tf
from flask import Flask, request, jsonify
import pandas as pd
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Conv2D, MaxPooling2D, Flatten, Dense
from sklearn.model_selection import train_test_split
import numpy as np

app = Flask(__name__)

# Global model variable
model = None

def load_data(file_path):
    data = pd.read_csv(file_path)
    # Assuming the CSV has columns 'image_path' and 'label'
    images = []
    labels = []
    for index, row in data.iterrows():
        image = tf.keras.preprocessing.image.load_img(row['image_path'], target_size=(64, 64))
        image_array = tf.keras.preprocessing.image.img_to_array(image) / 255.0
        images.append(image_array)
        labels.append(row['label'])
    return np.array(images), np.array(labels)

def create_model():
    global model
    model = Sequential([
        Conv2D(32, (3, 3), activation='relu', input_shape=(64, 64, 3)),
        MaxPooling2D((2, 2)),
        Flatten(),
        Dense(128, activation='relu'),
        Dense(10, activation='softmax')  # Assuming 10 classes
    ])
    model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])

@app.route('/train', methods=['POST'])
def train():
    file = request.files['file']
    file_path = '/tmp/train_data.csv'
    file.save(file_path)
    
    images, labels = load_data(file_path)
    X_train, X_val, y_train, y_val = train_test_split(images, labels, test_size=0.2, random_state=42)
    
    if model is None:
        create_model()
    
    model.fit(X_train, y_train, epochs=10, validation_data=(X_val, y_val))
    
    return jsonify({'status': 'success', 'message': 'Model trained successfully'})

@app.route('/predict', methods=['POST'])
def predict():
    file = request.files['file']
    image = tf.keras.preprocessing.image.load_img(file.stream, target_size=(64, 64))
    image_array = tf.keras.preprocessing.image.img_to_array(image) / 255.0
    image_array = np.expand_dims(image_array, axis=0)
    
    predictions = model.predict(image_array)
    predicted_label = np.argmax(predictions[0])
    
    return jsonify({'prediction': int(predicted_label)})

if __name__ == '__main__':
    app.run(debug=True)